<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Exploded Rubik's Cube — Generative Art</title>
  <style>
    * { margin: 0; padding: 0; box-sizing: border-box; }
    html, body {
      width: 100%; height: 100%;
      overflow: hidden;
      background: #08080c;
    }
    body {
      display: flex;
      align-items: center;
      justify-content: center;
      font-family: 'SF Mono', 'Fira Code', 'Cascadia Code', 'Consolas', monospace;
    }
    canvas { display: block; touch-action: none; }
    .ui {
      position: fixed;
      color: rgba(255,255,255,0.22);
      font-size: 10px;
      letter-spacing: 0.08em;
      text-transform: uppercase;
      pointer-events: none;
      z-index: 10;
    }
    #label { top: 22px; left: 26px; font-size: 11px; }
    #label span { color: rgba(255,255,255,0.10); margin: 0 6px; }
    #seed-info { top: 22px; right: 26px; }
    #hint { bottom: 22px; left: 26px; line-height: 1.8; text-transform: none; letter-spacing: 0.03em; }
    #pause-badge {
      position: fixed; top: 50%; left: 50%;
      transform: translate(-50%, -50%);
      color: rgba(255,255,255,0.12);
      font-size: 13px;
      letter-spacing: 0.15em;
      text-transform: uppercase;
      pointer-events: none;
      z-index: 10;
      display: none;
    }
    #vignette {
      position: fixed; inset: 0;
      background: radial-gradient(ellipse at center, transparent 50%, rgba(0,0,0,0.55) 100%);
      pointer-events: none;
      z-index: 5;
    }
  </style>
</head>
<body>
  <div id="label" class="ui">Rubik's Cube<span>/</span>Exploded View</div>
  <div id="seed-info" class="ui">seed <span id="sv">42</span></div>
  <div id="hint" class="ui">drag to orbit · scroll to zoom · click to reseed · space to pause</div>
  <div id="pause-badge">paused</div>
  <div id="vignette"></div>

  <script src="https://cdnjs.cloudflare.com/ajax/libs/p5.js/1.9.0/p5.min.js"></script>
  <script>
    let seed = 42;
    let cubies = [];
    let userRotX = -0.42;
    let userRotY = 0.62;
    let camDist = 560;
    let paused = false;
    let dragging = false;
    let dragTotal = 0;
    let pmx = 0, pmy = 0;

    const CUBIE = 50;
    const GAP = 6;
    const EXPLODE = 1.72;

    const COL = {
      R: [192, 32, 36],
      O: [228, 132, 28],
      W: [242, 242, 242],
      Y: [242, 212, 32],
      G: [28, 162, 68],
      B: [28, 78, 188],
    };

    function setup() {
      let sz = max(300, min(windowWidth, windowHeight));
      let c = createCanvas(sz, sz, WEBGL);
      c.style('background', 'transparent');
      pixelDensity(min(2, displayDensity()));
      buildCubies();
    }

    function buildCubies() {
      randomSeed(seed);
      noiseSeed(seed);
      cubies = [];
      for (let gx = -1; gx <= 1; gx++) {
        for (let gy = -1; gy <= 1; gy++) {
          for (let gz = -1; gz <= 1; gz++) {
            let axes = ['x', 'y', 'z'];
            let sa = axes[floor(random(3))];
            let sang = floor(random(4)) * HALF_PI;
            let scramble = random() > 0.42;
            cubies.push({
              gx, gy, gz,
              phase: random(TWO_PI),
              bobAmp: random(1.5, 5.5),
              bobSpd: random(0.18, 0.55),
              driftAmp: random(0.8, 3.2),
              driftSpd: random(0.08, 0.35),
              driftPh: random(TWO_PI),
              sAxis: scramble ? sa : null,
              sAngle: scramble ? sang : 0,
              microX: random(-0.025, 0.025),
              microY: random(-0.025, 0.025),
            });
          }
        }
      }
      document.getElementById('sv').textContent = seed;
    }

    function draw() {
      background(12, 12, 18);
      camera(0, 0, camDist, 0, 0, 0, 0, 1, 0);

      ambientLight(48, 48, 55);
      directionalLight(210, 215, 225, 0.45, 0.55, -0.7);
      directionalLight(70, 75, 95, -0.5, -0.35, 0.55);
      pointLight(55, 55, 75, 250, -350, 250);

      let t = paused ? 0 : frameCount * 0.015;
      let autoR = paused ? 0 : frameCount * 0.002;

      rotateY(userRotY + autoR);
      rotateX(userRotX);

      noStroke();

      for (let c of cubies) {
        let bob = sin(t * c.bobSpd + c.phase) * c.bobAmp;
        let dx = sin(t * c.driftSpd + c.driftPh) * c.driftAmp;
        let dz = cos(t * c.driftSpd * 0.7 + c.driftPh) * c.driftAmp;

        let sp = (CUBIE + GAP) * EXPLODE;
        let px = c.gx * sp + dx;
        let py = c.gy * sp + bob;
        let pz = c.gz * sp + dz;

        push();
        translate(px, py, pz);

        if (!paused) {
          rotateX(c.microX * sin(t * 0.3 + c.phase));
          rotateY(c.microY * cos(t * 0.25 + c.phase));
        }

        if (c.sAxis === 'x') rotateX(c.sAngle);
        else if (c.sAxis === 'y') rotateY(c.sAngle);
        else if (c.sAxis === 'z') rotateZ(c.sAngle);

        drawCubie(CUBIE, c.gx, c.gy, c.gz);
        pop();
      }
    }

    function drawCubie(s, gx, gy, gz) {
      let h = s / 2;
      let fs = s * 0.87;
      let off = h + 0.5;

      ambientMaterial(26, 26, 30);
      box(s);

      if (gx === 1) {
        push();
        rotateY(HALF_PI);
        translate(0, 0, off);
        specularMaterial(COL.R[0], COL.R[1], COL.R[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }

      if (gx === -1) {
        push();
        rotateY(-HALF_PI);
        translate(0, 0, off);
        specularMaterial(COL.O[0], COL.O[1], COL.O[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }

      if (gy === -1) {
        push();
        rotateX(HALF_PI);
        translate(0, 0, off);
        specularMaterial(COL.W[0], COL.W[1], COL.W[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }

      if (gy === 1) {
        push();
        rotateX(-HALF_PI);
        translate(0, 0, off);
        specularMaterial(COL.Y[0], COL.Y[1], COL.Y[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }

      if (gz === 1) {
        push();
        translate(0, 0, off);
        specularMaterial(COL.G[0], COL.G[1], COL.G[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }

      if (gz === -1) {
        push();
        rotateY(PI);
        translate(0, 0, off);
        specularMaterial(COL.B[0], COL.B[1], COL.B[2]);
        shininess(75);
        plane(fs, fs);
        pop();
      }
    }

    function mousePressed() {
      dragging = true;
      dragTotal = 0;
      pmx = mouseX;
      pmy = mouseY;
    }

    function mouseDragged() {
      if (!dragging) return;
      let dx = mouseX - pmx;
      let dy = mouseY - pmy;
      dragTotal += abs(dx) + abs(dy);
      userRotY += dx * 0.008;
      userRotX += dy * 0.008;
      userRotX = constrain(userRotX, -HALF_PI * 0.92, HALF_PI * 0.92);
      pmx = mouseX;
      pmy = mouseY;
    }

    function mouseReleased() {
      if (dragTotal < 5) reseed();
      dragging = false;
    }

    function mouseWheel(e) {
      camDist += e.delta * 0.8;
      camDist = constrain(camDist, 240, 1200);
      return false;
    }

    function keyPressed() {
      if (key === ' ') {
        paused = !paused;
        document.getElementById('pause-badge').style.display = paused ? 'block' : 'none';
      } else if (key === 'r' || key === 'R') {
        reseed();
      }
    }

    function reseed() {
      seed = floor(random(100000));
      buildCubies();
    }

    function windowResized() {
      let sz = max(300, min(windowWidth, windowHeight));
      resizeCanvas(sz, sz);
    }
  </script>
</body>
</html>
</artifact>
